def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        remainder = capacity - item
        for j in range(1, 10):
            term = ((-1) ** (j+1)) * (ratio ** j) / j
            score += term
            if term < 0.01:
                break
        if remainder < 0.1 * capacity:
            score *= 2
        elif remainder < 0.25 * capacity:
            score *= 1.5
        else:
            score *= 1.1
        if capacity % 3 == 0:
            score -= 0.2
        elif capacity % 5 == 0:
            score -= 0.15
        else:
            score -= 0.05
        if score < 0:
            score = 0
        priorities[i] = score
    for k in range(len(priorities)):
        if priorities[k] == 0:
            priorities[k] = np.nan
    return priorities
